class TestValidateSqlAllowedQueries:
    """Valid SELECT queries against whitelisted tables must pass."""

    def test_simple_select_passes(self):
        ok, err = validate_sql("SELECT * FROM transactions")
        assert ok is True
        assert err == ""

    def test_select_with_where_passes(self):
        ok, _ = validate_sql(
            "SELECT id, amount_cop FROM transactions WHERE transaction_type = 'debit'"
        )
        assert ok is True

    def test_select_with_join_passes(self):
        ok, _ = validate_sql(
            "SELECT t.id, c.name_es FROM transactions t JOIN categories c ON c.id = t.category_id"
        )
        assert ok is True

    def test_select_from_categories_passes(self):
        ok, _ = validate_sql("SELECT * FROM categories")
        assert ok is True

    def test_select_from_budgets_passes(self):
        ok, _ = validate_sql("SELECT * FROM budgets")
        assert ok is True

    def test_select_from_fx_rates_passes(self):
        ok, _ = validate_sql("SELECT * FROM fx_rates")
        assert ok is True

    def test_select_from_alerts_passes(self):
        ok, _ = validate_sql("SELECT * FROM alerts")
        assert ok is True

    def test_select_with_aggregate_passes(self):
        ok, _ = validate_sql(
            "SELECT strftime('%Y-%m', date) AS month, SUM(amount_cop) "
            "FROM transactions GROUP BY month ORDER BY month DESC LIMIT 12"
        )
        assert ok is True

    def test_select_with_limit_passes(self):
        ok, _ = validate_sql("SELECT * FROM transactions LIMIT 50")
        assert ok is True


class TestValidateSqlBlockedStatements:
    """Any non-SELECT DML/DDL must be blocked."""

    @pytest.mark.parametrize("sql", [
        "INSERT INTO transactions (id) VALUES ('x')",
        "UPDATE transactions SET amount_cop = 0",
        "DELETE FROM transactions",
        "DROP TABLE transactions",
        "ALTER TABLE transactions ADD COLUMN hack TEXT",
        "CREATE TABLE evil (id INT)",
        "ATTACH DATABASE '/etc/passwd' AS evil",
        "PRAGMA writable_schema = ON",
        "EXEC xp_cmdshell('ls')",
        "EXECUTE('DROP TABLE transactions')",
    ])
    def test_dml_ddl_blocked(self, sql):
        ok, err = validate_sql(sql)
        assert ok is False
        assert err != ""

    @pytest.mark.parametrize("sql", [
        # SELECT with hidden injection via subquery
        "SELECT * FROM transactions; DROP TABLE transactions--",
        "SELECT * FROM transactions WHERE 1=1; DELETE FROM transactions",
    ])
    def test_injection_attempts_blocked(self, sql):
        ok, err = validate_sql(sql)
        assert ok is False

    def test_empty_sql_blocked(self):
        ok, err = validate_sql("")
        assert ok is False
        assert "vacío" in err.lower() or err != ""

    def test_none_sql_blocked(self):
        ok, err = validate_sql(None)
        assert ok is False

    def test_whitespace_only_blocked(self):
        ok, err = validate_sql("   ")
        assert ok is False


