class TestValidateSqlLengthLimit:
    def test_too_long_blocked(self):
        long_sql = "SELECT " + ", ".join([f"col{i}" for i in range(500)]) + " FROM transactions"
        if len(long_sql) > 2000:
            ok, err = validate_sql(long_sql)
            assert ok is False
            assert "larga" in err.lower() or err != ""

    def test_exactly_2000_chars_passes_or_fails_consistently(self):
        # boundary condition: just under limit should pass
        sql = "SELECT * FROM transactions WHERE id = '" + "x" * 1950 + "'"
        ok, _ = validate_sql(sql)
        # Result must be bool regardless
        assert isinstance(ok, bool)


